def _render_previews_html(
    entries: list[dict], timestamp: str, repo_slug: str = "theexperiencecompany/gaia"
) -> str:
    def dot(svc: str, health: dict) -> str:
        st = health.get(svc, "unknown")
        color = {
            "healthy": "#22c55e",
            "running": "#22c55e",
            "unhealthy": "#ef4444",
            "stopped": "#ef4444",
        }.get(st, "#eab308")
        return (
            f'<span style="display:inline-flex;align-items:center;gap:4px;'
            f'font-size:11px;color:#a1a1aa">'
            f'<span style="width:8px;height:8px;border-radius:50%;'
            f'background:{color};flex-shrink:0"></span>{svc}</span>'
        )

    cards = ""
    if not entries:
        cards = (
            '<p style="color:#71717a;text-align:center;grid-column:1/-1;padding:40px">'
            "No active previews</p>"
        )
    for e in entries:
        label = "develop" if e["is_develop"] else f"PR #{e['pr_number']}"
        dots = "&nbsp;&nbsp;".join(dot(s, e["health"]) for s in ("api", "web", "worker"))
        teardown_btn = ""
        if not e["is_develop"]:
            pr_num_val = e["pr_number"]
            teardown_btn = (
                f'<button onclick="teardown({pr_num_val})" '
                f'style="background:transparent;border:1px solid #3f3f46;color:#71717a;'
                f'padding:6px 0;border-radius:8px;font-size:12px;cursor:pointer;width:100%">'
                f'Remove staging label</button>'
            )
        cards += (
            f'<div style="background:#18181b;border:1px solid #27272a;border-radius:12px;'
            f'padding:20px;display:flex;flex-direction:column;gap:12px">'
            f'<div><div style="font-weight:600;font-size:15px;color:#f4f4f5">{label}</div>'
            f'<div style="font-size:11px;color:#52525b;margin-top:3px">'
            f'sha: {e["sha"]} &middot; port: {e["port"]}</div></div>'
            f'<div style="display:flex;gap:12px;flex-wrap:wrap">{dots}</div>'
            f'<a href="{e["url"]}" target="_blank"'
            f' style="display:block;text-align:center;background:#3f3f46;color:#f4f4f5;'
            f'text-decoration:none;padding:8px 0;border-radius:8px;font-size:13px;font-weight:500">'
            f'Open Preview</a>'
            f'<a href="/logs" target="_blank"'
            f' style="text-align:center;color:#52525b;text-decoration:none;font-size:12px">'
            f'View Logs</a>'
            f'{teardown_btn}'
            f"</div>"
        )

    js = f"""
<script>
const REPO = '{repo_slug}';
function getToken() {{
  let t = localStorage.getItem('gh_pat');
  if (!t) {{
    t = prompt('Enter your GitHub Personal Access Token (repo scope):');
    if (t) localStorage.setItem('gh_pat', t.trim());
  }}
  return t ? t.trim() : null;
}}
function showMsg(id, msg, ok) {{
  const el = document.getElementById(id);
  if (!el) return;
  el.textContent = msg;
  el.style.color = ok ? '#22c55e' : '#ef4444';
  el.style.display = 'block';
}}
async function deploy() {{
  const pr = document.getElementById('pr-input').value.trim().replace(/^#/, '');
  if (!pr || isNaN(Number(pr))) {{ showMsg('deploy-msg', 'Enter a valid PR number', false); return; }}
  const token = getToken();
  if (!token) return;
  showMsg('deploy-msg', 'Applying staging label...', true);
  try {{
    const r = await fetch(`https://api.github.com/repos/${{REPO}}/issues/${{pr}}/labels`, {{
      method: 'POST',
      headers: {{'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json'}},
      body: JSON.stringify({{labels: ['staging']}})
    }});
    if (r.ok) {{
      showMsg('deploy-msg', `Label applied to PR #${{pr}}. Preview deploying in <60s.`, true);
      document.getElementById('pr-input').value = '';
    }} else {{
      const d = await r.json();
      showMsg('deploy-msg', `GitHub error: ${{d.message || r.status}}`, false);
    }}
  }} catch(e) {{ showMsg('deploy-msg', 'Request failed: ' + e.message, false); }}
}}
async function teardown(pr) {{
  if (!confirm(`Remove staging label from PR #${{pr}}? The preview will be torn down.`)) return;
  const token = getToken();
  if (!token) return;
  try {{
    const r = await fetch(`https://api.github.com/repos/${{REPO}}/issues/${{pr}}/labels/staging`, {{
      method: 'DELETE',
      headers: {{'Authorization': 'Bearer ' + token}}
    }});
    if (r.ok || r.status === 404) {{
      alert(`Staging label removed from PR #${{pr}}. Preview will be torn down in <60s.`);
    }} else {{
      const d = await r.json().catch(() => ({{}}));
      alert(`Error: ${{d.message || r.status}}`);
    }}
  }} catch(e) {{ alert('Request failed: ' + e.message); }}
}}
document.getElementById('pr-input').addEventListener('keydown', e => {{ if (e.key === 'Enter') deploy(); }});
</script>"""

    deploy_section = (
        '<div style="background:#18181b;border:1px solid #27272a;border-radius:12px;'
        'padding:20px;margin-bottom:24px">'
        '<div style="font-weight:600;font-size:14px;margin-bottom:12px">Deploy a PR preview</div>'
        '<div style="display:flex;gap:8px;align-items:center">'
        '<input id="pr-input" type="text" placeholder="PR number" '
        'style="background:#09090b;border:1px solid #3f3f46;color:#f4f4f5;padding:8px 12px;'
        'border-radius:8px;font-size:13px;width:140px;outline:none">'
        '<button onclick="deploy()" '
        'style="background:#3f3f46;color:#f4f4f5;border:none;padding:8px 16px;'
        'border-radius:8px;font-size:13px;font-weight:500;cursor:pointer">Deploy</button>'
        '<button onclick="localStorage.removeItem(\'gh_pat\')" '
        'style="background:transparent;border:none;color:#52525b;font-size:11px;cursor:pointer">'
        'reset token</button>'
        '</div>'
        '<div id="deploy-msg" style="font-size:12px;margin-top:8px;display:none"></div>'
        '</div>'
    )

    return (
        "<!DOCTYPE html>\n"
        '<html lang="en">\n'
        "<head>\n"
        '<meta charset="UTF-8">\n'
        '<meta http-equiv="refresh" content="30">\n'
        '<meta name="viewport" content="width=device-width,initial-scale=1">\n'
        "<title>Gaia Staging Previews</title>\n"
        "</head>\n"
        '<body style="margin:0;font-family:-apple-system,BlinkMacSystemFont,\'Segoe UI\','
        'sans-serif;background:#09090b;color:#f4f4f5;min-height:100vh;padding:32px 24px">\n'
        '<div style="max-width:900px;margin:0 auto">\n'
        '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:28px">\n'
        '<h1 style="margin:0;font-size:20px;font-weight:600">Gaia Staging Previews</h1>\n'
        '<div style="display:flex;gap:20px;align-items:center">\n'
        '<a href="/logs" target="_blank" style="color:#71717a;text-decoration:none;font-size:13px">'
        "Logs</a>\n"
        f'<span style="font-size:12px;color:#3f3f46">Updated {timestamp}</span>\n'
        "</div>\n</div>\n"
        f"{deploy_section}\n"
        '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:16px">\n'
        f"{cards}\n"
        "</div>\n</div>\n"
        f"{js}\n"
        "</body>\n</html>\n"
    )


def _write_previews_index(
    cfg: object,
    project: object,
    deployed: dict,
    public_host: str,
) -> None:
    """Write staging-infra/previews/index.html listing all active PR previews."""
    from datetime import datetime, timezone

    from previewctl.docker_ops import DockerPreviewSpec, docker_stack_status
    from previewctl.port_pool import PortPool

    pool = PortPool(cfg.runtime_dir / "docker-port-pool.json")
    allocations = pool.list_allocations()

    entries: list[dict] = []
    for pr_num, port in sorted(allocations.items(), key=lambda x: x[1]):
        is_develop = pr_num == project.develop_pr_number
        slug = "develop" if is_develop else f"pr-{pr_num}"
        url = f"{project.public_scheme}://{public_host}:{port}"
        sha = (deployed.get(pr_num) or "")[:7] or "?"

        spec = DockerPreviewSpec(
            pr_number=pr_num,
            api_image="",
            web_image="",
            staging_infra_dir=cfg.staging_infra_dir,
            runtime_dir=cfg.runtime_dir,
            public_base_domain="",
            public_scheme=project.public_scheme,
            core_network=cfg.compose_network,
        )
        raw = docker_stack_status(spec)
        health: dict[str, str] = {}
        for name, status in raw.items():
            svc = name.rsplit("-", 1)[-1]
            sl = status.lower()
            if "unhealthy" in sl or "exited" in sl:
                health[svc] = "unhealthy"
            elif "healthy" in sl:
                health[svc] = "healthy"
            elif sl.startswith("up"):
                health[svc] = "running"
            else:
                health[svc] = "stopped"

        entries.append(
            {
                "pr_number": pr_num,
                "slug": slug,
                "url": url,
                "port": port,
                "sha": sha,
                "is_develop": is_develop,
                "health": health,
            }
        )

    ts = datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M UTC")
    repo_slug = getattr(project, "repo_slug", "") or "theexperiencecompany/gaia"

