                health[svc] = "running"
            else:
                health[svc] = "stopped"

        entries.append(
            {
                "pr_number": pr_num,
                "slug": slug,
                "url": url,
                "port": port,
                "sha": sha,
                "is_develop": is_develop,
                "health": health,
            }
        )

    ts = datetime.now(UTC).strftime("%Y-%m-%d %H:%M UTC")
    repo_slug = getattr(project, "repo_slug", "") or "theexperiencecompany/gaia"
    html = _render_previews_html(entries, ts, repo_slug=repo_slug)
    out_dir = cfg.staging_infra_dir / "previews"
    out_dir.mkdir(parents=True, exist_ok=True)
    (out_dir / "index.html").write_text(html, encoding="utf-8")
    typer.echo(f"[previews] index written ({len(entries)} previews)")


