def _list_open_prs_by_label(
    repo_slug: str,
    labels: list[str],
    base_branch: str,
    workspace_root: Path,
) -> list[dict[str, object]]:
    if not labels:
        return []

    # Use REST API endpoint — gh pr list --search has a known issue where
    # label filtering via GitHub's search index returns stale/empty results
    # even when PRs have the label. The pulls REST endpoint is authoritative.
    label_expr = ",".join(labels)
    required = {lbl.lower() for lbl in labels}
    selected: list[dict[str, object]] = []
    page = 1
    while True:
        page_data = _json_cmd_output(
            [
                "gh",
                "api",
                f"/repos/{repo_slug}/pulls",
                "--method",
                "GET",
                "-f",
                "state=open",
                "-f",
                f"base={base_branch}",
                "-f",
                f"labels={label_expr}",
                "-f",
                "per_page=100",
                "-f",
                f"page={page}",
            ],
            workspace_root,
        )
        if not isinstance(page_data, builtins.list):
            break
        if not page_data:
            break
        for item in page_data:
            if not isinstance(item, dict):
                continue
            pr_number = item.get("number")
            updated_at = item.get("updated_at")
            head = item.get("head")
            pr_labels = item.get("labels")
            if not isinstance(pr_number, int):
                continue
            sha = head.get("sha") if isinstance(head, dict) else None
            if not isinstance(sha, str):
                continue
            # Double-check label membership (API filter is AND for multiple labels)
            if not isinstance(pr_labels, builtins.list):
                continue
            names: set[str] = set()
            for label in pr_labels:
                if isinstance(label, dict):
                    name = label.get("name")
                    if isinstance(name, str):
                        names.add(name.lower())
            if not required.intersection(names):
                continue
            selected.append(
                {
                    "number": pr_number,
                    "sha": sha,
                    "updatedAt": updated_at,
                }
            )
        if len(page_data) < 100:
            break
        page += 1

    def _sort_key(item: dict[str, object]) -> tuple[str, int]:
        updated = item.get("updatedAt")
        updated_key = str(updated) if isinstance(updated, str) else ""
        return (updated_key, int(item["number"]))

    selected.sort(key=_sort_key, reverse=True)
    return selected


