def _image_tag(pr_number: int, service: str, sha: str) -> str:
    slug = "develop" if pr_number == project.develop_pr_number else f"pr-{pr_number}"
    short = sha[:7]
    return f"gaia-staging/{service}:{slug}-{short}"

def _run_once() -> None:
    with _project_env(project):
        cfg = load_config()

    # --- Fetch desired state from GitHub ---
    repo_slug = project.repo_slug or _repo_slug_from_origin(project.app_repo)
    labeled_prs = _list_open_prs_by_label(
        repo_slug=repo_slug,
        labels=project.labels,
        base_branch=project.base_branch,
        workspace_root=project.workspace_root,
    )
    desired: dict[int, str] = {}  # pr_number → sha

    # Develop branch is always included as pr-0
    if project.include_develop:
        develop_pr = project.develop_pr_number
        try:
            dev_sha = _run_cmd(
                ["git", "ls-remote", "origin", f"refs/heads/{develop_branch}"],
                project.app_repo,
            )
            dev_sha = dev_sha.split()[0] if dev_sha else ""
        except Exception:
            dev_sha = ""
        if dev_sha:
            desired[develop_pr] = dev_sha

    for item in labeled_prs[: project.max_previews]:
        pr_num = int(item["number"])
        desired[pr_num] = str(item["sha"])

    # --- Deploy new / updated previews ---
    with _project_env(project):
        cfg = load_config()
        for pr_num, sha in desired.items():
            if deployed.get(pr_num) == sha:
                continue
            is_develop = pr_num == project.develop_pr_number
            branch_ref = develop_branch if is_develop else f"pull/{pr_num}/head"
            worktree = (
                project.runtime_dir
                / "worktrees"
                / ("develop" if is_develop else f"pr-{pr_num}")
            )
            try:
                old_sha = deployed.get(pr_num)
                _ensure_gaia_worktree(project.app_repo, worktree, branch_ref)
                actual_sha = _run_cmd(["git", "rev-parse", "HEAD"], worktree)
                api_tag = _image_tag(pr_num, "api", actual_sha)
                web_tag = _image_tag(pr_num, "web", actual_sha)

                if build:
                    _docker_build_images(worktree, pr_num, branch_ref, api_tag, web_tag)

                url = _docker_deploy_pr(
                    cfg, pr_num, actual_sha, api_tag, web_tag, public_host_resolved
                )
                deployed[pr_num] = actual_sha
                typer.echo(
                    f"[{datetime.now().isoformat()}] pr={pr_num} sha={actual_sha[:7]} url={url}"
                )
                # Remove previous images now that the new stack is up
                if old_sha and old_sha != actual_sha:
                    _docker_remove_images(
                        [
                            _image_tag(pr_num, "api", old_sha),
                            _image_tag(pr_num, "web", old_sha),
                        ]
                    )
            except Exception as exc:
                typer.echo(f"[{datetime.now().isoformat()}] pr={pr_num} deploy failed: {exc}")

        # --- Tear down stale previews ---
        from previewctl.port_pool import PortPool

        pool = PortPool(cfg.runtime_dir / "docker-port-pool.json")
        for pr_num in list(pool.list_allocations().keys()):
            if pr_num not in desired:
                typer.echo(
                    f"[{datetime.now().isoformat()}] pr={pr_num} tearing down (no longer desired)"
                )
                old_sha = deployed.get(pr_num)
                try:
                    _docker_teardown_pr(cfg, pr_num, public_host_resolved)
                    deployed.pop(pr_num, None)
                    # Remove images after containers are stopped
                    if old_sha:
                        _docker_remove_images(
                            [
                                _image_tag(pr_num, "api", old_sha),
                                _image_tag(pr_num, "web", old_sha),
                            ]
                        )
                except Exception as exc:
                    typer.echo(
                        f"[{datetime.now().isoformat()}] pr={pr_num} teardown failed: {exc}"
                    )

        # Regenerate the /previews index page after every poll cycle.
        try:
            _write_previews_index(cfg, project, deployed, public_host_resolved)
        except Exception as exc:
            typer.echo(f"[{datetime.now().isoformat()}] previews index write failed: {exc}")

